  6→export function createProject(name = 'Untitled Project') {
  7→  return {
  8→    id: generateId('proj'),
  9→    name,
 10→    createdAt: new Date().toISOString(),
 11→    updatedAt: new Date().toISOString(),
 12→    floors: [createFloor('Ground Floor', 0, { elevation: 0, floorToFloorHeight: WALL_HEIGHT })],
 13→    sheets: [],
 14→    version: 1,
 15→  };
 16→}
 17→
 18→export function createFloor(name = 'Floor', levelIndex = 0, options = {}) {
 19→  const floorToFloorHeight = options.floorToFloorHeight ?? WALL_HEIGHT;
 20→  const elevation = options.elevation ?? (levelIndex * floorToFloorHeight);
 21→
 22→  return {
 23→    id: generateId('floor'),
 24→    name,
 25→    levelIndex,
 26→    elevation,
 27→    floorToFloorHeight,
 28→    walls: [],
 29→    rooms: [],
 30→    doors: [],
 31→    windows: [],
 32→    columns: [],
 33→    beams: [],
 34→    stairs: [],
 35→    landings: [],
 36→    fixtures: [],
 37→    annotations: [],
 38→    annotationSettings: createAnnotationSettings(),
 39→    slabs: [],
 40→    sectionCuts: [],
 41→  };
 42→}
 43→
 44→export function nextSectionLabel(existingCuts = []) {
 45→  const usedLetters = new Set(
 46→    existingCuts
 47→      .map(c => {
 48→        const match = c.label?.match(/^Section\s+([A-Z])-\1$/);
 49→        return match ? match[1] : null;
 50→      })
 51→      .filter(Boolean)
 52→  );
 53→  for (let i = 0; i < 26; i++) {
 54→    const letter = String.fromCharCode(65 + i);
 55→    if (!usedLetters.has(letter)) return `Section ${letter}-${letter}`;
 56→  }
 57→  return `Section ${existingCuts.length + 1}`;
 58→}
