 1→import { createFixture } from '@/domain/models';
 2→import { GRID_MINOR } from '@/domain/defaults';
 3→import { FIXTURE_TYPES } from '@/editor/tools';
 4→
 5→function snapToGrid(value) {
 6→  return Math.round(value / GRID_MINOR) * GRID_MINOR;
 7→}
 8→
 9→export function createFixturePlaceHandler({ dispatch, editorDispatch, getFloor, activeFloorId, snapEnabled }) {
10→  return {
11→    onMouseMove(modelPos) {
12→      let x = modelPos.x;
13→      let y = modelPos.y;
14→      if (snapEnabled) {
15→        x = snapToGrid(x);
16→        y = snapToGrid(y);
17→      }
18→      editorDispatch({
19→        type: 'UPDATE_TOOL_STATE',
20→        payload: { previewX: x, previewY: y },
21→      });
22→    },
23→
24→    onMouseDown(modelPos, e, toolState) {
25→      if (e.button !== 0) return;
26→      let x = modelPos.x;
27→      let y = modelPos.y;
28→      if (snapEnabled) {
29→        x = snapToGrid(x);
30→        y = snapToGrid(y);
31→      }
32→      const fixtureType = toolState?.fixtureType || FIXTURE_TYPES.KITCHEN_TOP;
33→      const rotation = toolState?.previewRotation || 0;
34→      const fixture = createFixture(fixtureType, x, y, { rotation });
35→      dispatch({ type: 'FIXTURE_ADD', floorId: activeFloorId, fixture });
36→    },
37→
38→    onKeyDown(e, toolState) {
39→      if (e.key.toLowerCase() === 'r' && !e.ctrlKey && !e.metaKey) {
40→        e.preventDefault();
41→        const current = toolState?.previewRotation || 0;
42→        const next = (current + 90) % 360;
43→        editorDispatch({
44→          type: 'UPDATE_TOOL_STATE',
45→          payload: { previewRotation: next },
46→        });
47→      } else if (e.key === 'Escape') {
48→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
49→      }
50→    },
51→
52→    getCursor() {
53→      return 'crosshair';
54→    },
55→  };
56→}
