413→function createObjectForDescriptor(descriptor, materialPalette, isSelected) {
414→  if (descriptor.geometry === 'prism') {
415→    return createPrismObject(descriptor, materialPalette, isSelected);
416→  }
417→
418→  if (descriptor.geometry === 'stair') {
419→    return createStairObject(descriptor, materialPalette, isSelected);
420→  }
421→
422→  if (descriptor.geometry === 'window') {
423→    return createWindowObject(descriptor, materialPalette, isSelected);
424→  }
425→
426→  if (descriptor.geometry === 'fixture') {
427→    return createFixtureObject(descriptor, materialPalette, isSelected);
428→  }
429→
430→  return createBoxObject(descriptor, materialPalette, isSelected);
431→}
